 94→fn detect_content_type(content: &str) -> &'static str {
 95→    let trimmed = content.trim();
 96→
 97→    if trimmed.starts_with("http://") || trimmed.starts_with("https://") {
 98→        return "link";
 99→    }
100→
101→    if (trimmed.len() == 4 || trimmed.len() == 7 || trimmed.len() == 9)
102→        && trimmed.starts_with('#')
103→        && trimmed[1..].chars().all(|c| c.is_ascii_hexdigit())
104→    {
105→        return "color";
106→    }
107→
108→    if trimmed.starts_with("rgb(")
109→        || trimmed.starts_with("rgba(")
110→        || trimmed.starts_with("hsl(")
111→        || trimmed.starts_with("hsla(")
112→    {
113→        return "color";
114→    }
115→
116→    "text"
117→}
